class Solution:
    def count(self, num1: str, num2: str, min_sum: int, max_sum: int) -> int:
        MOD = 10**9 + 7

        def count_up_to(s):
            n = len(s)
            digits = [int(c) for c in s]
            memo = {}

            def dp(pos, digit_sum, tight):
                if digit_sum > max_sum:
                    return 0
                if pos == n:
                    return 1 if min_sum <= digit_sum <= max_sum else 0
                key = (pos, digit_sum, tight)
                if key in memo:
                    return memo[key]
                limit = digits[pos] if tight else 9
                result = 0
                for d in range(limit + 1):
                    result = (result + dp(pos + 1, digit_sum + d, tight and d == limit)) % MOD
                memo[key] = result
                return result

            return dp(0, 0, True)

        def decrement(s):
            s = list(s)
            i = len(s) - 1
            while i >= 0 and s[i] == '0':
                s[i] = '9'
                i -= 1
            if i >= 0:
                s[i] = str(int(s[i]) - 1)
            result = ''.join(s).lstrip('0')
            return result if result else '0'

        num1_dec = decrement(num1)
        result = (count_up_to(num2) - count_up_to(num1_dec)) % MOD
        return result

