class Solution:
    def longestSemiRepetitiveSubstring(self, s: str) -> int:
        n = len(s)
        if n <= 2:
            return n
        left = 0
        count = 0
        max_len = 1
        for right in range(1, n):
            if s[right] == s[right - 1]:
                count += 1
            while count > 1:
                if s[left] == s[left + 1]:
                    count -= 1
                left += 1
            max_len = max(max_len, right - left + 1)
        return max_len

class Solution:
    def circularGameLosers(self, n: int, k: int) -> list[int]:
        visited = [False] * n
        pos = 0
        turn = 1
        visited[0] = True
        while True:
            pos = (pos + turn * k) % n
            if visited[pos]:
                break
            visited[pos] = True
            turn += 1
        return [i + 1 for i in range(n) if not visited[i]]

