class Solution:
    def minimizeConcatenatedLength(self, words: list[str]) -> int:
        n = len(words)
        if n == 1:
            return len(words[0])

        INF = float('inf')
        # dp[first][last] = min length with given first and last chars
        dp = [[INF] * 26 for _ in range(26)]

        # Initialize with first word
        w = words[0]
        fc = ord(w[0]) - ord('a')
        lc = ord(w[-1]) - ord('a')
        dp[fc][lc] = len(w)

        for i in range(1, n):
            w = words[i]
            wf = ord(w[0]) - ord('a')
            wl = ord(w[-1]) - ord('a')
            wlen = len(w)

            new_dp = [[INF] * 26 for _ in range(26)]

            for fc in range(26):
                for lc in range(26):
                    if dp[fc][lc] == INF:
                        continue

                    # Option 1: join(str, w) - append w to the right
                    if lc == wf:
                        cost = dp[fc][lc] + wlen - 1
                    else:
                        cost = dp[fc][lc] + wlen
                    if cost < new_dp[fc][wl]:
                        new_dp[fc][wl] = cost

                    # Option 2: join(w, str) - prepend w to the left
                    if wl == fc:
                        cost = dp[fc][lc] + wlen - 1
                    else:
                        cost = dp[fc][lc] + wlen
                    if cost < new_dp[wf][lc]:
                        new_dp[wf][lc] = cost

            dp = new_dp

        result = INF
        for i in range(26):
            for j in range(26):
                if dp[i][j] < result:
                    result = dp[i][j]
        return result

class Solution:
    def maximumJumps(self, nums: list[int], target: int) -> int:
        n = len(nums)
        dp = [-1] * n
        dp[0] = 0
        for j in range(1, n):
            for i in range(j):
                if dp[i] != -1 and abs(nums[j] - nums[i]) <= target:
                    dp[j] = max(dp[j], dp[i] + 1)
        return dp[n - 1]

class Solution:
    def countCompleteSubarrays(self, nums: list[int]) -> int:
        k = len(set(nums))
        n = len(nums)
        if k == 1:
            return n * (n + 1) // 2
        count = 0
        freq = {}
        distinct = 0
        right = 0
        for left in range(n):
            while right < n and distinct < k:
                if freq.get(nums[right], 0) == 0:
                    distinct += 1
                freq[nums[right]] = freq.get(nums[right], 0) + 1
                right += 1
            if distinct == k:
                count += n - right + 1
            freq[nums[left]] -= 1
            if freq[nums[left]] == 0:
                distinct -= 1
        return count

