class Solution:
    def minimumIndex(self, nums: list[int]) -> int:
        # Boyer-Moore to find dominant element
        candidate = 0
        count = 0
        for num in nums:
            if count == 0:
                candidate = num
                count = 1
            elif num == candidate:
                count += 1
            else:
                count -= 1
        # Count total occurrences of dominant element
        total = sum(1 for x in nums if x == candidate)
        n = len(nums)
        # Scan for minimum valid split
        prefix_count = 0
        for i in range(n - 1):
            if nums[i] == candidate:
                prefix_count += 1
            prefix_len = i + 1
            suffix_len = n - 1 - i
            suffix_count = total - prefix_count
            if prefix_count * 2 > prefix_len and suffix_count * 2 > suffix_len:
                return i
        return -1

