class Solution:
    def countSteppingNumbers(self, low: str, high: str) -> int:
        MOD = 10**9 + 7

        def count_leq(s):
            n = len(s)
            digits = list(map(int, s))
            memo = {}

            def dp(pos, prev, tight, started):
                if pos == n:
                    return 1 if started else 0
                key = (pos, prev, tight, started)
                if key in memo:
                    return memo[key]

                limit = digits[pos] if tight else 9
                result = 0
                for d in range(limit + 1):
                    if not started:
                        if d == 0:
                            result += dp(pos + 1, 0, tight and d == limit, False)
                        else:
                            result += dp(pos + 1, d, tight and d == limit, True)
                    else:
                        if abs(d - prev) == 1:
                            result += dp(pos + 1, d, tight and d == limit, True)

                result %= MOD
                memo[key] = result
                return result

            return dp(0, 0, True, False)

        def dec(s):
            lst = list(s)
            i = len(lst) - 1
            while i >= 0 and lst[i] == '0':
                lst[i] = '9'
                i -= 1
            lst[i] = str(int(lst[i]) - 1)
            result = ''.join(lst)
            return result.lstrip('0') or '0'

        return (count_leq(high) - count_leq(dec(low))) % MOD

