class Solution:
    def maxSum(self, nums: List[int], m: int, k: int) -> int:
        if len(nums) < k:
            return 0
        freq = Counter(nums[:k])
        current_sum = sum(nums[:k])
        max_sum = current_sum if len(freq) >= m else 0
        for i in range(k, len(nums)):
            outgoing = nums[i - k]
            incoming = nums[i]
