class Solution:
    def getMaxFunctionValue(self, receiver: List[int], k: int) -> int:
        n = len(receiver)
        LOG = max(1, k.bit_length())
        next_node = [[0] * LOG for _ in range(n)]
        sum_node = [[0] * LOG for _ in range(n)]

        for i in range(n):
            next_node[i][0] = receiver[i]
            sum_node[i][0] = receiver[i]

        for j in range(1, LOG):
            for i in range(n):
                mid = next_node[i][j - 1]
                next_node[i][j] = next_node[mid][j - 1]
                sum_node[i][j] = sum_node[i][j - 1] + sum_node[mid][j - 1]

        ans = 0
        for x in range(n):
            result = x
            curr = x
            kk = k
            for j in range(LOG):
                if kk & (1 << j):
                    result += sum_node[curr][j]
                    curr = next_node[curr][j]
            ans = max(ans, result)

        return ans

