    def minOperations(self, nums1: List[int], nums2: List[int]) -> int:
        n = len(nums1)

        def solve(last1, last2):
            swaps = 0
            for i in range(n - 1):
                a, b = nums1[i], nums2[i]
                ok_orig = (a <= last1 and b <= last2)
                ok_swap = (b <= last1 and a <= last2)
                if ok_orig:
                    continue
                elif ok_swap:
                    swaps += 1
                else:
                    return float('inf')
            return swaps

        # Case 1: don't swap last element
        res1 = solve(nums1[-1], nums2[-1])
        # Case 2: swap last element
        res2 = solve(nums2[-1], nums1[-1])
        if res2 != float('inf'):
            res2 += 1

