                    x |= (1 << i)
            else:
                # Different bits: give 1 to smaller value to balance
                if (a ^ x) >= (b ^ x):
                    # a is larger or equal, give bit to b
                    if b_bit == 0:
                        x |= (1 << i)
                else:
                    # b is larger, give bit to a
                    if a_bit == 0:
                        x |= (1 << i)
        return ((a ^ x) * (b ^ x)) % MOD

