class Solution:
    def numberOfGoodPartitions(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        # Find first and last occurrence of each number
        first = {}
        last = {}
        for i, x in enumerate(nums):
            if x not in first:
                first[x] = i
            last[x] = i

        # Merge overlapping intervals
        intervals = [(first[x], last[x]) for x in first]
        intervals.sort()

        merged = []
        for start, end in intervals:
            if merged and start <= merged[-1][1]:
                merged[-1] = (merged[-1][0], max(merged[-1][1], end))
            else:
                merged.append((start, end))

        # Number of groups = len(merged)
        # Between consecutive groups, we can cut or not
        # Answer = 2^(len(merged) - 1)
        return pow(2, len(merged) - 1, MOD)

