class Solution:
    def countCompleteSubstrings(self, word: str, k: int) -> int:
        def count_in_segment(segment):
            res = 0
            n = len(segment)
            for d in range(1, 27):
                length = d * k
                if length > n:
                    break
                freq = [0] * 26
                valid = 0
                for i in range(n):
                    idx = ord(segment[i]) - ord('a')
                    freq[idx] += 1
                    if freq[idx] == k:
                        valid += 1
                    elif freq[idx] == k + 1:
                        valid -= 1
                    if i >= length:
                        idx_out = ord(segment[i - length]) - ord('a')
                        if freq[idx_out] == k:
                            valid -= 1
                        elif freq[idx_out] == k + 1:
                            valid += 1
                        freq[idx_out] -= 1
                    if i >= length - 1 and valid == d:
                        res += 1
            return res

        result = 0
        start = 0
        for i in range(1, len(word)):
            if abs(ord(word[i]) - ord(word[i - 1])) > 2:
                result += count_in_segment(word[start:i])
                start = i
        result += count_in_segment(word[start:])
        return result

class Solution:
    def numberOfSequence(self, n: int, sick: list[int]) -> int:
        MOD = 10**9 + 7

        fact = [1] * (n + 1)
        for i in range(1, n + 1):
            fact[i] = fact[i - 1] * i % MOD

        inv_fact = [1] * (n + 1)
        inv_fact[n] = pow(fact[n], MOD - 2, MOD)
        for i in range(n - 1, -1, -1):
            inv_fact[i] = inv_fact[i + 1] * (i + 1) % MOD

        segments = []
        if sick[0] > 0:
            segments.append((False, sick[0]))
        for i in range(len(sick) - 1):
            gap = sick[i + 1] - sick[i] - 1
            if gap > 0:
                segments.append((True, gap))
        if sick[-1] < n - 1:
            segments.append((False, n - 1 - sick[-1]))

        total = sum(size for _, size in segments)

        result = fact[total]
        for _, size in segments:
            result = result * inv_fact[size] % MOD

        for is_middle, size in segments:
            if is_middle and size > 0:
                result = result * pow(2, size - 1, MOD) % MOD

        return result

