class Solution:
    def maxPartitionsAfterOperations(self, s: str, k: int) -> int:
        if k >= 26:
            return 1

        n = len(s)
        s_int = [ord(c) - 97 for c in s]

        from functools import lru_cache

        @lru_cache(maxsize=None)
        def dp(i, mask, changed):
            if i == n:
                return 1

            c = s_int[i]
            new_mask = mask | (1 << c)

            best = 0

            # Don't change s[i]
            if bin(new_mask).count('1') <= k:
                best = dp(i + 1, new_mask, changed)
            else:
                best = 1 + dp(i + 1, 1 << c, changed)

            # Change s[i] to some other letter
            if not changed:
                for nc in range(26):
                    nm = mask | (1 << nc)
                    if bin(nm).count('1') <= k:
                        val = dp(i + 1, nm, True)
                    else:
                        val = 1 + dp(i + 1, 1 << nc, True)
                    if val > best:
                        best = val

            return best

        result = dp(0, 0, False)
        dp.cache_clear()
        return result

