class Solution:
    def numberOfPowerfulInt(self, start: int, finish: int, limit: int, s: str) -> int:
        s_val = int(s)
        k = len(s)
        power = 10 ** k

        def count_valid_prefixes(m):
            """Count numbers from 0 to m where all digits are <= limit."""
            if m < 0:
                return 0
            digits = str(m)
            n = len(digits)
            count = 0
            for i in range(n):
                d = int(digits[i])
                remaining = n - 1 - i
                if d > 0:
                    upper = min(d - 1, limit)
                    if upper >= 0:
                        count += (upper + 1) * (limit + 1) ** remaining
                if d > limit:
                    break
            else:
                count += 1
            return count

        def count_up_to(n):
            """Count powerful integers in [1, n]."""
            if n < s_val:
                return 0
            m = (n - s_val) // power
            return count_valid_prefixes(m)

        return count_up_to(finish) - count_up_to(start - 1)

