class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        n = len(s)
        la, lb = len(a), len(b)

        # Find all occurrences of a in s
        a_indices = []
        for i in range(n - la + 1):
            if s[i:i + la] == a:
                a_indices.append(i)

        # Find all occurrences of b in s
        b_indices = []
        for i in range(n - lb + 1):
            if s[i:i + lb] == b:
                b_indices.append(i)

        if not b_indices:
            return []

        # For each a_index, check if there's a b_index within k using binary search
        result = []
        for ai in a_indices:
            pos = bisect_left(b_indices, ai)
            found = False
            if pos < len(b_indices) and b_indices[pos] - ai <= k:
                found = True
            if pos > 0 and ai - b_indices[pos - 1] <= k:
                found = True
            if found:
                result.append(ai)

        return result

