class Solution:
    def earliestSecondToMarkIndices(self, nums: list[int], changeIndices: list[int]) -> int:
        n = len(nums)
        m = len(changeIndices)

        def check(s):
            last = {}
            for i in range(s):
                last[changeIndices[i]] = i
            if len(last) != n:
                return False
            sorted_indices = sorted(last.keys(), key=lambda x: last[x])
            cum_decrement = 0
            for k, idx in enumerate(sorted_indices):
                pos = last[idx]
                cum_decrement += nums[idx - 1]
                free = pos - k
                if free < cum_decrement:
                    return False
            return True

        total_needed = sum(nums) + n
        if total_needed > m:
            return -1

        lo, hi = total_needed, m
        result = -1
        while lo <= hi:
            mid = (lo + hi) // 2
            if check(mid):
                result = mid
                hi = mid - 1
            else:
                lo = mid + 1

        return result

