class Solution:
    def sumOfPowers(self, nums: List[int], k: int) -> int:
        MOD = 10**9 + 7
        nums.sort()
        n = len(nums)

        # Collect all distinct pairwise differences
        diffs_set = set()
        for i in range(n):
            for j in range(i + 1, n):
                diffs_set.add(nums[j] - nums[i])
        diffs = sorted(diffs_set)

        def count_ge(threshold):
            """Count subsequences of length k where all consecutive gaps >= threshold."""
            dp = [1] * n
            for j in range(2, k + 1):
                prefix = [0] * (n + 1)
                for i in range(n):
                    prefix[i + 1] = (prefix[i] + dp[i]) % MOD
                new_dp = [0] * n
                for i in range(n):
                    if threshold <= 0:
                        p = i - 1
                    else:
                        p = bisect.bisect_right(nums, nums[i] - threshold) - 1
                        if p >= i:
                            p = i - 1
                    if p >= 0:
                        new_dp[i] = prefix[p + 1]
                dp = new_dp
            return sum(dp) % MOD

        ans = 0
        m = len(diffs)
        for idx in range(m):
            d = diffs[idx]
            c1 = count_ge(d)
            if idx + 1 < m:
                c2 = count_ge(diffs[idx + 1])
            else:
                c2 = 0
            contribution = d * ((c1 - c2) % MOD) % MOD
            ans = (ans + contribution) % MOD

        return ans

