class Solution:
    def minimumMoves(self, nums: List[int], k: int, maxChanges: int) -> int:
        ones = [i for i, v in enumerate(nums) if v == 1]
        n = len(ones)

        if n == 0:
            return 2 * k

        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + ones[i]

        def get_cost(l, r):
            """Cost to collect ones[l..r-1] to their median position."""
            m = l + r
            if m % 2 == 0:
                mid = m // 2
                return (ones[mid] * (mid - l) - (prefix[mid] - prefix[l])) + (
                    (prefix[r] - prefix[mid]) - ones[mid] * (r - mid)
                )
            else:
                mid1 = m // 2
                mid2 = mid1 + 1
                cost1 = (ones[mid1] * (mid1 - l) - (prefix[mid1] - prefix[l])) + (
                    (prefix[r] - prefix[mid1]) - ones[mid1] * (r - mid1)
                )
                cost2 = (ones[mid2] * (mid2 - l) - (prefix[mid2] - prefix[l])) + (
                    (prefix[r] - prefix[mid2]) - ones[mid2] * (r - mid2)
                )
                return min(cost1, cost2)

        ans = float('inf')

        for i in range(n):
            alice = ones[i]
            used = 0
            need = k

            # Check adjacent positions for free ones
            if need > 0 and nums[alice] == 1:
                need -= 1
            for d in [1, -1]:
                if need > 0 and 0 <= alice + d < len(nums) and nums[alice + d] == 1:
                    need -= 1
                    used += 1
            for d in [2, -2]:
                if need > 0 and 0 <= alice + d < len(nums) and nums[alice + d] == 1:
                    need -= 1
                    used += 2

            # Use maxChanges for remaining
            use_changes = min(need, maxChanges)
            cost = used + use_changes * 2
            need -= use_changes

            if need <= 0:
                ans = min(ans, cost)
                continue

            # Need 'need' more ones from the ones array via swaps
            # Find the best window of 'need' ones from the array
            if need > n:
                continue

            best_window = float('inf')
            for left in range(n - need + 1):
                right = left + need
                c = get_cost(left, right)
                if c < best_window:
                    best_window = c

            if best_window < float('inf'):
                ans = min(ans, cost + best_window)

        return ans

import math


class Solution:
    def minOperations(self, k: int) -> int:
        if k <= 1:
            return 0
        best = k  # worst case: increase by k-1, no duplicates
        for v in range(1, k + 1):
            c = math.ceil(k / v)
            ops = (v - 1) + (c - 1)
            if ops < best:
                best = ops
        return best

