class Solution:
    def sumOfPower(self, nums: List[int], k: int) -> int:
        MOD = 10**9 + 7
        n = len(nums)
        # dp[s][j] = number of subsets with sum s and size j
        dp = [[0] * (n + 1) for _ in range(k + 1)]
        dp[0][0] = 1

        for num in nums:
            for s in range(k, num - 1, -1):
                for j in range(n, 0, -1):
                    dp[s][j] = (dp[s][j] + dp[s - num][j - 1]) % MOD

        # Precompute powers of 2
        pow2 = [1] * (n + 1)
        for i in range(1, n + 1):
            pow2[i] = pow2[i - 1] * 2 % MOD

        ans = 0
        for j in range(n + 1):
            ans = (ans + dp[k][j] * pow2[n - j]) % MOD

        return ans

class Solution:
    def getSmallestString(self, s: str, k: int) -> str:
        result = []
        for c in s:
            offset = ord(c) - ord('a')
            cost_to_a = min(offset, 26 - offset)
            if cost_to_a <= k:
                result.append('a')
                k -= cost_to_a
            else:
                result.append(chr(ord(c) - k))
                k = 0
        return ''.join(result)

