class Solution:
    def shortestSubstrings(self, arr: list[str]) -> list[str]:
        n = len(arr)
        # Precompute all substrings for each string
        all_substrings = []
        for s in arr:
            subs = set()
            for i in range(len(s)):
                for j in range(i + 1, len(s) + 1):
                    subs.add(s[i:j])
            all_substrings.append(subs)

        result = []
        for i in range(n):
            found = ""
            s = arr[i]
            # Try substrings by increasing length
            for length in range(1, len(s) + 1):
                candidates = []
                for start in range(len(s) - length + 1):
                    sub = s[start:start + length]
                    # Check if sub appears in any other string
                    in_other = False
                    for j in range(n):
                        if j != i and sub in all_substrings[j]:
                            in_other = True
                            break
                    if not in_other:
                        candidates.append(sub)
                if candidates:
                    candidates.sort()
                    found = candidates[0]
                    break
            result.append(found)
        return result

