class Solution:
    def minimumDeletions(self, word: str, k: int) -> int:
        freq = Counter(word)
        freqs = list(freq.values())
        min_deletions = float('inf')
        for f in freqs:
            deletions = 0
            for freq_val in freqs:
                if freq_val > f + k:
                    deletions += freq_val - (f + k)
                elif freq_val < f:
                    deletions += freq_val
            min_deletions = min(min_deletions, deletions)
        return min_deletions

