class Solution:
    def minEnd(self, n: int, x: int) -> int:
        n -= 1
        result = x
        bit_pos = 0
        while n > 0:
            while (x >> bit_pos) & 1:
                bit_pos += 1
            if n & 1:
                result |= (1 << bit_pos)
            n >>= 1
            bit_pos += 1
        return result

