class Solution:
    def minimumSubstringsInPartition(self, s: str) -> int:
        n = len(s)
        dp = [float('inf')] * (n + 1)
        dp[0] = 0
        for i in range(n):
            if dp[i] == float('inf'):
                continue
            freq = {}
            for j in range(i, n):
                freq[s[j]] = freq.get(s[j], 0) + 1
                vals = freq.values()
                if len(set(vals)) == 1:
                    dp[j + 1] = min(dp[j + 1], dp[i] + 1)
        return dp[n]
